// src/pages/Hero.jsx

export default function Hero() {

  return (

    <div style={styles.page}>

      <div style={styles.hero}>

        <h1 style={styles.title}>
          Hire Trusted Daily Workers Easily
        </h1>

        <p style={styles.subtitle}>
          Find skilled workers near your area
        </p>

        <div style={styles.buttons}>

          <button
            style={styles.loginBtn}
            onClick={() =>
              window.location = "/login"
            }
          >
            Login
          </button>

          <button
            style={styles.registerBtn}
            onClick={() =>
              window.location = "/register"
            }
          >
            Register
          </button>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f4f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  hero: {
    textAlign: "center"
  },

  title: {
    fontSize: "55px",
    color: "#111827"
  },

  subtitle: {
    fontSize: "18px",
    color: "#6b7280",
    marginTop: "10px",
    marginBottom: "30px"
  },

  buttons: {
    display: "flex",
    justifyContent: "center",
    gap: "15px"
  },

  loginBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px 30px",
    borderRadius: "10px",
    cursor: "pointer"
  },

  registerBtn: {
    background: "white",
    border: "1px solid #d1d5db",
    padding: "14px 30px",
    borderRadius: "10px",
    cursor: "pointer"
  }

};
